import{_ as t,o as a,c as i,a4 as s}from"./chunks/framework.DBZEZKAP.js";const u=JSON.parse('{"title":"Security Model","description":"","frontmatter":{},"headers":[],"relativePath":"security.md","filePath":"security.md","lastUpdated":null}'),n={name:"security.md"};function o(r,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="Security-Model" tabindex="-1">Security Model <a class="header-anchor" href="#Security-Model" aria-label="Permalink to &quot;Security Model {#Security-Model}&quot;">​</a></h1><p>Kaimon executes arbitrary Julia code on your machine, so controlling access is important. The security system provides three modes, API key authentication, and IP allowlisting to match different trust environments.</p><h2 id="Security-Modes" tabindex="-1">Security Modes <a class="header-anchor" href="#Security-Modes" aria-label="Permalink to &quot;Security Modes {#Security-Modes}&quot;">​</a></h2><p>Kaimon operates in one of three security modes:</p><h3 id="strict" tabindex="-1">Strict <a class="header-anchor" href="#strict" aria-label="Permalink to &quot;Strict&quot;">​</a></h3><p>API key is <strong>required</strong> for all requests. Any request without a valid key is rejected.</p><p>Best for:</p><ul><li><p>Production or shared servers.</p></li><li><p>Environments where multiple users or agents may connect.</p></li><li><p>Any situation where you want explicit access control.</p></li></ul><h3 id="relaxed" tabindex="-1">Relaxed <a class="header-anchor" href="#relaxed" aria-label="Permalink to &quot;Relaxed&quot;">​</a></h3><p>API key is <strong>optional</strong> but honored. Requests without a key are allowed, but if a key is provided, it must be valid.</p><p>Best for:</p><ul><li><p>Local development with some protection.</p></li><li><p>Environments where you want the option to authenticate without enforcing it globally.</p></li></ul><h3 id="lax" tabindex="-1">Lax <a class="header-anchor" href="#lax" aria-label="Permalink to &quot;Lax&quot;">​</a></h3><p><strong>No authentication</strong>. All requests are accepted regardless of whether a key is provided.</p><p>Best for:</p><ul><li><p>Fully trusted local environments.</p></li><li><p>Quick experimentation where security overhead is unnecessary.</p></li></ul><h2 id="API-Key-Management" tabindex="-1">API Key Management <a class="header-anchor" href="#API-Key-Management" aria-label="Permalink to &quot;API Key Management {#API-Key-Management}&quot;">​</a></h2><p>Kaimon provides functions to manage API keys:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Function</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Kaimon.generate_key()</code></td><td style="text-align:right;">Generate a new API key and register it with the server.</td></tr><tr><td style="text-align:right;"><code>Kaimon.revoke_key()</code></td><td style="text-align:right;">Revoke an existing API key so it can no longer be used.</td></tr><tr><td style="text-align:right;"><code>Kaimon.security_status()</code></td><td style="text-align:right;">Display the current security mode, active keys, and IP allowlist.</td></tr></tbody></table><h3 id="Using-API-Keys-with-MCP-Clients" tabindex="-1">Using API Keys with MCP Clients <a class="header-anchor" href="#Using-API-Keys-with-MCP-Clients" aria-label="Permalink to &quot;Using API Keys with MCP Clients {#Using-API-Keys-with-MCP-Clients}&quot;">​</a></h3><p>MCP clients authenticate by including the API key in the <code>X-API-Key</code> HTTP header. In your MCP client configuration, set the header:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;headers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;X-API-Key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-api-key-here&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The server validates this header on each request (in Strict and Relaxed modes).</p><h2 id="IP-Allowlists" tabindex="-1">IP Allowlists <a class="header-anchor" href="#IP-Allowlists" aria-label="Permalink to &quot;IP Allowlists {#IP-Allowlists}&quot;">​</a></h2><p>You can restrict which IP addresses are permitted to connect:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Function</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>allow_ip(ip)</code></td><td style="text-align:right;">Add an IP address to the allowlist. Only allowlisted IPs can connect.</td></tr><tr><td style="text-align:right;"><code>deny_ip(ip)</code></td><td style="text-align:right;">Remove an IP address from the allowlist.</td></tr></tbody></table><p>When the allowlist is empty, all IPs are permitted (subject to API key requirements based on the security mode). Once at least one IP is added to the allowlist, only those IPs are accepted.</p><h2 id="Gate-TCP-Authentication" tabindex="-1">Gate (TCP) Authentication <a class="header-anchor" href="#Gate-TCP-Authentication" aria-label="Permalink to &quot;Gate (TCP) Authentication {#Gate-TCP-Authentication}&quot;">​</a></h2><p>The sections above govern the <strong>MCP HTTP server</strong>. A separate concern is the <strong>gate</strong> (<code>KaimonGate</code>) when it binds a TCP socket for remote access — see <a href="/Kaimon.jl/dev/gate#tcp-mode">TCP Mode</a>. The gate enforces its own token, independent of the MCP server&#39;s API keys:</p><ul><li><p><strong>Standalone <code>KaimonGate</code></strong> (the lightweight <code>]add KaimonGate</code> install, e.g. on a remote/compute node): the gate token comes <strong>only</strong> from the <code>KAIMON_GATE_TOKEN</code> environment variable. If it is unset, the TCP gate is <strong>open</strong> — any client that can reach the port can evaluate code in the session. Always set <code>KAIMON_GATE_TOKEN</code> before exposing a gate on a shared or network-reachable host (and prefer binding to <code>127.0.0.1</code> + an SSH tunnel over <code>0.0.0.0</code>).</p></li><li><p><strong>Full <code>Kaimon</code></strong> install: the token is taken from <code>KAIMON_GATE_TOKEN</code> if set, otherwise derived from your security config&#39;s API keys when the config mode is not <code>:lax</code>. So a strict/relaxed config automatically protects TCP gates started by that process.</p></li></ul><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>IPC (Unix-socket) gates are protected by filesystem permissions on <code>~/.cache/kaimon/sock/</code> and do not use a token. The token only applies to TCP mode. A <code>0.0.0.0</code> bind with no token exposes a remote code-execution endpoint to the network.</p></div><h2 id="Encrypted-Transport-CURVE" tabindex="-1">Encrypted Transport (CURVE) <a class="header-anchor" href="#Encrypted-Transport-CURVE" aria-label="Permalink to &quot;Encrypted Transport (CURVE) {#Encrypted-Transport-CURVE}&quot;">​</a></h2><p>A bearer token proves <em>who may call</em> a TCP gate, but it travels in the clear and the traffic is unencrypted. For a gate exposed beyond <code>localhost</code>, enable <strong>CURVE</strong> — ZMQ&#39;s Curve25519 transport — for confidentiality, integrity, and <strong>mutual</strong> authentication on the wire. CURVE replaces the SSH tunnel as the security layer (server pinning + a client allow-list), and its <strong>soy-free mode</strong> SSH-bootstraps the server pin to close the TOFU first-use gap entirely.</p><p>See <strong><a href="./curve">Encrypted Transport (CURVE)</a></strong> for the full trust model, key management (<code>[k]</code> in the TUI), soy-free verification, and stall diagnostics.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Security settings are stored in a global JSON configuration file:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/kaimon/config.json</span></span></code></pre></div><p>Legacy <code>security.json</code> files are automatically migrated to <code>config.json</code> on first access.</p><h3 id="Configuration-Format" tabindex="-1">Configuration Format <a class="header-anchor" href="#Configuration-Format" aria-label="Permalink to &quot;Configuration Format {#Configuration-Format}&quot;">​</a></h3><p>A typical <code>config.json</code> file:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;strict&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;api_keys&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;key-abc123...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;allowed_ips&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;127.0.0.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;::1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="Setup-Wizard" tabindex="-1">Setup Wizard <a class="header-anchor" href="#Setup-Wizard" aria-label="Permalink to &quot;Setup Wizard {#Setup-Wizard}&quot;">​</a></h2><p>For interactive configuration, use the setup wizard:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Kaimon</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Kaimon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setup_wizard_tui</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>The wizard walks you through:</p><ol><li><p>Choosing a security mode (Strict, Relaxed, or Lax).</p></li><li><p>Generating an initial API key.</p></li><li><p>Configuring IP allowlists.</p></li><li><p>Writing the configuration file to the appropriate location.</p></li></ol><p>This is the recommended way to configure security for the first time.</p>`,47)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
